mapper.select:
SELECT a.*, b.form_schema, b.form_config FROM workflow_form_binding a LEFT JOIN form_definition b ON a.form_key = b.form_code WHERE a.del_flag = 0
AND process_definition_key = #{processDefinitionKey}
AND task_definition_key = #{taskDefinitionKey}
ORDER BY form_type, task_name

mapper.update:
UPDATE workflow_form_binding SET del_flag = 1
WHERE process_definition_key = #{processDefinitionKey}
AND task_definition_key = #{taskDefinitionKey}
